var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"옛날 옛날에 운명을 볼 줄 아는 여인이 있었다네.","JPN":"むかしむかし、運命を見ることのできる女がいた。","ENG":"Long long ago, there once lived a maiden whose gift was to foresee what lay ahead.","TWN":"很久很久以前，有個懂得算命的女人。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그 여인은 자신이 가장 사랑하는 가족의 죽음을 막기 위해 목숨을 대신 바쳤지.","JPN":"その女はもっとも愛する家族を死から遠ざける代償として自らの命を捧げた。","ENG":"The maiden offered up her own life as sacrifice, to save her most beloved family member.","TWN":"她因為要拯救心愛的家族免於一死，而獻出自己的性命。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 여인의 희생을 원통하게 여긴 가족은 모든 인간을 증오하며 눈 먼 복수를 하게 됐어.","JPN":"しかし、女の犠牲を無念に思った家族は人間すべてを憎み、復讐の鬼と化して復讐をするようになった。","ENG":"Alas, fortune took an unexpected turn. Her family became enraged at her death, taking vengeance on all of mankind.","TWN":"然而家族對於女人的犧牲感到憤恨不平，因此憎恨人類，於是展開盲目的報復。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"여인의 희생이 무색하게도, 그녀의 가족은 죽음보다 더한 복수의 굴레에 갇히고 말았다네.","JPN":"女の犠牲も無駄となるくらい、彼女の家族は死よりもひどい復讐という檻に囚われてしまったとさ。","ENG":"The maiden’s sacrifice went to vain, and her family lives on, bound by the curse of vengeance... a curse far more daunting than death itself.","TWN":"結果女人的犧牲完全是白費力氣，她的家族則是困在比死亡更痛苦的復仇牢籠裡。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"어때? 운명이라는 건 참 얄궂지 않나?","JPN":"どうだい？　運命とは実に皮肉じゃのう。","ENG":"What do you say? Fate can be ever so deceitful, no?","TWN":"怎麼樣？命運這回事很折騰人吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUEST_VOICE_NULL_NULL","text":{"KOREA":"하하…… 네에……","JPN":"はは……そうですねえ……","ENG":"Ha ha... I see...","TWN":"哈哈……是啊……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"주인장~ 한 그릇 더~","JPN":"ご主人～おかわりじゃ～","ENG":"Hey! Another bowl!","TWN":"老闆～再來一碗～"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"저 애 벌써 우동만 다섯 그릇째야. 저러고도 괜찮은 건가?","JPN":"あの子、もううどん五杯目だよ。大丈夫なのかな？","ENG":"That girl’s on her fifth bowl of noodles. Is she all right?","TWN":"那女生已經吃第五碗烏龍麵咧？她沒問題吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"아니, 난 그것보다 머리에 달려 있는 게 신경 쓰이는데.","JPN":"私はそれより頭についているものの方が気になるんだけど。","ENG":"I’m more puzzled about that thing on her head.","TWN":"比起烏龍麵，她頭上的東西更令人在意吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"어디서 코스프레 행사라도 있었나 보지.","JPN":"どこかでコスプレのイベントでもあったんでしょ。","ENG":"Maybe she was at some sort of cosplay convention.","TWN":"可能是剛參加完Cosplay活動吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"코스프레 치고는 꼬리가 움직이고 있지 않아?","JPN":"コスプレにしちゃあ尻尾が動いてない？","ENG":"You do realize her tail is moving, as if it’s alive... right?","TWN":"Cosplay有這麼厲害？尾巴還會動？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"푸하- 역시 속세의 요리는 세월이 흘러도 변함 없이 맛있구나.","JPN":"ぷっはー、やはり浮世の料理は月日がたっても相変わらず美味いものじゃのう。","ENG":"Gah! Food in the modern world is still delicious as always.","TWN":"噗哈- 俗世的料理果然不管過多久都一樣好吃！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"오? 거기 빤히 쳐다보는 녀석. 나한테 할말이라도 있냐?","JPN":"お？　こちらをまじまじと見ているそこの者。何か言いたいことでもあるのか？","ENG":"Oh? You there, the fellow staring at me. You have something to say?","TWN":"嗯？那邊那個一直盯著我瞧的小夥子，你有話要跟我說嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"아…… 아뇨, 시비 걸겠다는 건 아니고…… 조금 신기해보여서요.","JPN":"あ……いえ、ケンカを売るつもりは全然ないんですが……ちょっと不思議で。","ENG":"N-no, I don’t mean any harm... I just thought you looked rather interesting.","TWN":"沒……沒有，我沒有要挑釁的意思……我只是覺得很新奇。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"오! 내 장비에 관심이 있는 게로구나?","JPN":"おお！　わしの装備に興味があるのだな？","ENG":"Aha! You’re amazed by my gears, are you not?","TWN":"喔！你對我的裝備有興趣是嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"좋다! 그 안목을 높이 사서 특별히 내 제자로 받아 주마!","JPN":"よかろう！　その目を高く評価して、特別にわしの弟子にしてやろうではないか！","ENG":"Fate has smiled upon you, young one! I shall accept you as my pupil, just this once!","TWN":"好！看在你這麼有眼光的份上，我就破例收你當徒弟吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"너, 용광로 다루는 법 정도는 알고 있겠지?","JPN":"お主、溶鉱炉を扱う方法くらいは知っておるだろうな？","ENG":"I assume you know your way with blast furnaces, hmm?","TWN":"喂，你知道怎麼使用熔爐吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"네? 용광…… 로?","JPN":"はい？　溶鉱……炉？","ENG":"Sorry? A blast... what?","TWN":"什麼？熔爐……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"모르는 거냐? 어쩔 수 없지. 그럼 가장 기초 중의 기초부터 빠르게 가르쳐볼까?","JPN":"知らぬのか？　仕方ないのう。それでは、基本中の基本からちゃちゃっと教えてやろう。","ENG":"You don’t? Shame, but no harm in that. I will teach you the basics of basics, quick-style!","TWN":"你不會喔？真拿你沒辦法，那我就從最基本的開始教你吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"저기, 딱히 뭘 배우려는 생각은 없어요. 회사일이 바빠서 취미 가질 시간이 없거든요.","JPN":"あの、別に何かを教わる気はないんです。会社の仕事が忙しくて趣味活動をする暇がないんで。","ENG":"Um, I don’t want to learn anything new. I’m already caught up with my current job.","TWN":"那個，我沒有想要學東西的意思，公司的事就夠我忙了，我沒時間培養興趣。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"하루 다섯 시간! 아니, 세 시간만 할애하거라! 이 몸이 오십 년 안에 네 녀석을 최고의 대장장이로 만들어주마!","JPN":"一日5時間！　いや、3時間だけでいいのじゃ！　わしが50年以内にお主を最高の鍛冶屋にしてやろう！","ENG":"Five hours daily! No, three! I shall make you the best blacksmith on earth, in only fifty years!","TWN":"一天五小時！不，三小時就好！我會讓你在五十年內成為最頂尖的鐵匠！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"말이 잘 안 통하는 것 같은데……","JPN":"話が通じない……","ENG":"I don’t think she’s getting it...","TWN":"她好像聽不懂我的意思……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"슬슬 자리를 옮겨야겠지?","JPN":"そろそろ移動した方が良さそうだね。","ENG":"We should probably move places now.","TWN":"我們還是換個位置吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"돈도 주겠다! 물동이를 푸거나 나무를 베어오라고 시키지도 않을 테니까!","JPN":"給料も出そう！　水を汲んで来いだとか、木を斬り倒せだとかも言わん！","ENG":"I will pay you, even! You will be relieved of the tedious chores of chopping wood or fetching water!","TWN":"我還會給你錢！也不會叫你去打水或是砍柴！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GUEST_VOICE_NULL_B","text":{"KOREA":"죄송해요. 믿는 종교가 이미 있어서요.","JPN":"すみません。宗教なら間に合ってるんで。","ENG":"Sorry, I don’t talk to cultists.","TWN":"不好意思，我有其他信仰。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GUEST_VOICE_NULL_A","text":{"KOREA":"사장님, 여기 계산 좀 해주세요.","JPN":"おじちゃん、お会計お願いします。","ENG":"Sir, I’d like my bill please.","TWN":"老闆，我們要結帳。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"자, 잠깐만……!","JPN":"ま、待てぃ……！","ENG":"W-wait!","TWN":"先…先等一下……！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"에잉…… 아쉽구만. 제법 팔심이 좋아 보이는 형씨였는데.","JPN":"むむ……残念じゃ。なかなか腕の力がありそうなやつだったんじゃが。","ENG":"What a shame. He looked like a fellow with good arm strength.","TWN":"哎呀……真可惜，那小夥子看起來體格不錯說。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"주인장~ 한 그릇만 더 내어주게~","JPN":"ご主人～もう一杯頼む～","ENG":"Hey! One more bowl, please!","TWN":"老闆～我要再來一碗～"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"같이 일할 분을 찾고 계시나 봐요?","JPN":"一緒に働く人をお探しで？","ENG":"So you’re looking for someone to work with?","TWN":"你是在找可以一起做事的人嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"뭐, 그런 셈이지. 간만의 외출이라 식도락을 겸해 제자를 알아보고 있다네. 나 혼자서는 언제 명맥이 끊길지 모르니 말이야.","JPN":"まあ、そんなところじゃな。久々の外出で食道楽もかねて弟子を探しておってな。一人ではいつ命脈が断たれるかわからんしのう。","ENG":"You could say that. I haven’t been out in town for a long time, so I’m seeking an apprentice while enjoying the gourmet culture here. With me as the sole artisan, our tradition is on the verge of extinction.","TWN":"嗯，算是吧，難得外出一趟，想說滿足口腹之慾的同時順便找個徒弟。畢竟只有我自己一個的話，不知道什麼時候會失傳。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"하지만 요즘 젊은 것들은 통 기술을 배우려고 하질 않는구만~","JPN":"それにしても、最近の若者は技術を教わろうという者がさっぱりおらんのう～","ENG":"But youngsters these days... They refuse to learn, don't they?","TWN":"不過最近的年輕人都不太想學一技之長呢～"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"다들 당장 오늘을 살아가는 것도 빠듯하니 그렇겠죠.","JPN":"みんな今日を生きることに精一杯だからでしょうね。","ENG":"I guess so. It’s hard enough to cope with living, you know.","TWN":"因為大家光是要活過今天都很辛苦吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"조금 잠잠하려나 싶으면 침식사태니 비상대피령이니, 여유를 가질 틈이 없다니까요.","JPN":"ちょっと落ち着いたと思ったら侵食事態だの非常退避令だので、余裕を持つ暇がないんですから。","ENG":"You get one day of peace and quiet, and the first thing that happens the next day is a Corruption disaster or an emergency evacuation. There’s no time for luxury or hobbies.","TWN":"想說終於可以稍微喘口氣，結果一下子發生侵蝕事件，一下子又要緊急避難，根本沒有喘息的空間。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"한 그릇 더!","JPN":"もう一杯！","ENG":"Another one!","TWN":"再來一碗！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L50_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"저기…… 돈은 있으신 거 맞죠?","JPN":"あの……お金はあるんですよね？","ENG":"Um... You do have enough money on you, right?","TWN":"這位客人……您身上的錢夠吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"돈……?","JPN":"お金……？","ENG":"Money...?","TWN":"什麼錢……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"이제 와서 뭡니까! 그 천연덕스럽게 시치미 떼겠다는 표정은!","JPN":"今更なんですか！　その何のことかわからないって顔は！","ENG":"Wait, don’t tell me you’re not going to pay for all of this!","TWN":"你現在在跟我裝什麼傻！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 또 침식경보라고?","JPN":"な、何だ？　また侵食警報？","ENG":"W-what? Another Corruption alert?","TWN":"怎…怎麼回事？又是侵蝕警報嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"……후루룩-","JPN":"……ズズズ～","ENG":"...*Slurrrppp*","TWN":"……呼嚕嚕-"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"저, 손님. 지금 우동을 먹고 있을 때가 아니라 빨리 대피소로 가야해요.","JPN":"お客さん。うどんすすってる場合じゃないですよ。早く退避所に向かわないと。","ENG":"Excuse me, miss. This isn’t the time to enjoy noodles. We have to evacuate, now!","TWN":"這位客人，你現在還有閒情逸致吃烏龍麵？快去避難所躲一下吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"음식을 식게 내버려둘 순 없지. 너 먼저 가거라.","JPN":"料理が冷めてしまってはいかんだろう。お主、先に行け。","ENG":"I can’t let a nice hot bowl of noodles go to waste. You go ahead.","TWN":"麵冷掉就不好吃咧，你先走吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"이봐요! 지금 음식 타령이나 할 때가 아니라니까……!","JPN":"あのね！　今は料理のことなんか考えてる場合じゃないんだって……！","ENG":"Hey! I’m telling you, this isn’t the time to sit around and eat–","TWN":"喂！現在麵冷掉是重點嗎……！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐야?!","JPN":"なっ、何だ！？","ENG":"W-what?!","TWN":"怎…怎麼會？！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"벌써 침식체가 여기까지……?","JPN":"もう侵食体がここまで……？","ENG":"There are C.O.s coming in already...?","TWN":"侵蝕體這麼快就進到這裡……？"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"마…… 망했다. 이미 빠져나가긴 글렀어.","JPN":"だ……ダメだ。もう逃げられない。","ENG":"I-I’m doomed. It’s too late now.","TWN":"唔……慘了，來不及逃了。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"크흡……! 청춘을 집 보증금만 갚으면서 다 바쳤는데…… 고작 이런 임대포장마차가 내 인생 최후의 업적이라니……","JPN":"くうっ……！　青春を家の保証金を返すことにすべて費やしたというのに……こんな貸し屋台程度で俺の人生が終わるなんて……","ENG":"Urgh...! I sacrificed all of my youth trying to pay back debt for the house... And now... a rented out street food restaurant is going to be my last and biggest accomplishment...?","TWN":"嗚嗚……！我的青春都拿來賺錢還房貸……沒想到這個路邊攤會是我最後的葬身之處……"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"쯧쯔, 입맛 떨어지게 사내녀석이 울고 자빠졌냐.","JPN":"おいおい、男が泣くではない。食欲がなくなるではないか。","ENG":"Tut tut, man up and stop wailing like a crybaby.","TWN":"嘖嘖，男子漢大丈夫哭什麼哭！害我都沒胃口了。"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"예……?","JPN":"はい……？","ENG":"Huh...?","TWN":"蛤……？"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"계산합세, 주인장. 저 놈들 한 마리에 우동 1인분으로 쳐주는 걸로.","JPN":"ご主人、お勘定を頼む。あいつら一匹につき、うどん1人前でな。","ENG":"Let’s do it this way. For each C.O. I take down, you take 1 bowl of noodles off my tab.","TWN":"老闆，算帳！一隻抵一碗麵的錢！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"아니, 이게 무슨 애들 장난입니까? 지금 돈 문제가 아니라 생사가 달렸다니까요.","JPN":"子どもの遊びじゃないんですから。今はお金が問題じゃなくて命がかかってるんですよ！","ENG":"Hey, this isn’t a joke! Our lives are at risk!","TWN":"胡說八道什麼，你在跟我開玩笑嗎？算什麼帳？我現在根本有錢也沒命花！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"이봐요……! 거기로 가면 안 됩니다……! 침식체들한테 들킨다고요……!","JPN":"ああっ……！　そっちに行っちゃいけません……！　侵食体にバレますって……！","ENG":"Hey...! You shouldn’t go there...! You’ll get spotted by the C.O.s...!","TWN":"喂……！不可以過去……！會被侵蝕體發現的……！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L33_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"한 방에…… 날아갔어? 저 커다란 침식체가?","JPN":"一発で……飛んだ？　あの大きな侵食体が？","ENG":"It got... taken down...? A C.O. that big...?","TWN":"立刻……被打飛咧？那麼大隻的侵蝕體？"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"우선 한 그릇.","JPN":"まずは一杯。","ENG":"That’s one bowl.","TWN":"廢話少說，再來一碗！"},"stage":{"bg":"CITY_CENTER2","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};